  1	import React, { Dispatch, FC, SetStateAction, useEffect, useState } from 'react';
  2	
  3	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
  4	import { IoK8sApiStorageV1StorageClass } from '@kubevirt-ui/kubevirt-api/kubernetes';
  5	import { V1beta1PersistentVolumeClaim } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import { getDefaultStorageClass } from '@kubevirt-utils/components/DiskModal/components/StorageClassAndPreallocation/utils/helpers';
  7	import Loading from '@kubevirt-utils/components/Loading/Loading';
  8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import useStorageProfileClaimPropertySets from '@kubevirt-utils/hooks/useStorageProfileClaimPropertySets';
 10	import { BinaryUnit } from '@kubevirt-utils/utils/units';
 11	import {
 12	  Alert,
 13	  AlertVariant,
 14	  Checkbox,
 15	  FileUpload,
 16	  Split,
 17	  SplitItem,
 18	} from '@patternfly/react-core';
 19	
 20	import {
 21	  getGiBUploadPVCSizeByImage,
 22	  getName,
 23	  getNamespace,
 24	  getTemplateOperatingSystems,
 25	} from '../utils/selectors';
 26	import { OperatingSystemRecord } from '../utils/types';
 27	import { updateDV } from '../utils/utils';
 28	
 29	import UploadPVCFormGoldenImage from './UploadPVCFormGoldenImage';
 30	import UploadPVCFormMode from './UploadPVCFormMode';
 31	import UploadPVCFormPVCName from './UploadPVCFormPVCName';
 32	import UploadPVCFormSize from './UploadPVCFormSize';
 33	import UploadPVCFormStorageClass from './UploadPVCFormStorageClass';
 34	
 35	import './upload-pvc-form.scss';
 36	
 37	type UploadPVCFormProps = {
 38	  commonTemplates: V1Template[];
 39	  fileName: string;
 40	  fileValue: File | string;
 41	  goldenPvcs: V1beta1PersistentVolumeClaim[];
 42	  handleFileChange: (_, value: File) => void;
 43	  handleFileNameChange: (event, file: string) => void;
 44	  isLoading: boolean;
 45	  ns: string;
 46	  onChange: (K8sResourceKind) => void;
 47	  osParam?: string;
 48	  setDisableFormSubmit: Dispatch<SetStateAction<boolean>>;
 49	  setIsFileRejected: Dispatch<SetStateAction<boolean>>;
 50	  storageClasses: IoK8sApiStorageV1StorageClass[];
 51	};
 52	
 53	const UploadPVCForm: FC<UploadPVCFormProps> = ({
 54	  commonTemplates,
 55	  fileName,
 56	  fileValue,
 57	  goldenPvcs,
 58	  handleFileChange,
 59	  handleFileNameChange,
 60	  isLoading,
 61	  ns,
 62	  onChange,
 63	  osParam,
 64	  setDisableFormSubmit,
 65	  setIsFileRejected,
 66	  storageClasses,
 67	}) => {
 68	  const { t } = useKubevirtTranslation();
 69	  const operatingSystems = getTemplateOperatingSystems(commonTemplates).filter(
 70	    (o) => !o?.isSourceRef,
 71	  );
 72	  const operatingSystemHaveDV = operatingSystems?.find(
 73	    (os) => os?.baseImageName && os?.baseImageNamespace,
 74	  );
 75	  const [storageClassName, setStorageClassName] = useState<string>('');
 76	  const [pvcName, setPvcName] = useState<string>('');
 77	  const [namespace, setNamespace] = useState<string>(ns);
 78	  const [accessMode, setAccessMode] = useState<string>('');
 79	  const [volumeMode, setVolumeMode] = useState<string>();
 80	  const [requestSizeValue, setRequestSizeValue] = useState<string>('');
 81	  const [requestSizeUnit, setRequestSizeUnit] = useState<string>('Gi');
 82	  const [isGolden, setIsGolden] = useState<boolean>(!!osParam);
 83	  const [os, setOs] = useState<OperatingSystemRecord>();
 84	  const [pvcSizeFromTemplate, setPvcSizeFromTemplate] = useState<boolean>(false);
 85	  const [mountAsCDROM, setMountAsCDROM] = useState<boolean>();
 86	  const [osImageExists, setOsImageExists] = useState<boolean>(false);
 87	  const defaultSCName = getDefaultStorageClass(storageClasses)?.metadata?.name;
 88	  const [applySP, setApplySP] = useState<boolean>(true);
 89	  const {
 90	    claimPropertySets,
 91	    error: loadError,
 92	    loaded: spLoaded,
 93	  } = useStorageProfileClaimPropertySets(storageClassName || defaultSCName);
 94	  const { accessModes: spAccessMode, volumeMode: spVolumeMode } = claimPropertySets?.[0] || {};
 95	
 96	  useEffect(() => {
 97	    !storageClassName && setStorageClassName(defaultSCName ?? storageClasses?.[0]?.metadata?.name);
 98	  }, [defaultSCName, storageClassName, storageClasses]);
 99	
100	  useEffect(() => {
101	    const value = getGiBUploadPVCSizeByImage((fileValue as File)?.size);
102	    const isIso = (fileValue as File)?.name?.toLowerCase().endsWith('.iso');
103	    setMountAsCDROM(isIso);
104	    setPvcSizeFromTemplate(!isIso);
105	    setRequestSizeValue(isIso ? value?.toString() : os?.baseImageRecomendedSize?.[0] || '');
106	    setRequestSizeUnit(os?.baseImageRecomendedSize[1] || BinaryUnit.Gi);
107	  }, [fileValue, os]);
108	
109	  useEffect(() => {
110	    if (storageClassName && spLoaded && applySP) {
111	      spAccessMode?.[0] !== accessMode && setAccessMode(spAccessMode?.[0]);
112	      spVolumeMode !== volumeMode && setVolumeMode(spVolumeMode);
113	    }
114	  }, [spLoaded, spAccessMode, spVolumeMode, accessMode, volumeMode, storageClassName, applySP]);
115	
116	  useEffect(() => {
117	    onChange(
118	      updateDV({
119	        accessMode,
120	        mountAsCDROM,
121	        namespace,
122	        pvcName,
123	        requestSizeUnit,
124	        requestSizeValue,
125	        storageClassName,
126	        volumeMode,
127	      }),
128	    );
129	  }, [
130	    accessMode,
131	    volumeMode,
132	    namespace,
133	    pvcName,
134	    onChange,
135	    mountAsCDROM,
136	    storageClassName,
137	    requestSizeValue,
138	    requestSizeUnit,
139	  ]);
140	
141	  const handleGoldenCheckbox = (checked: boolean) => {
142	    setIsGolden(checked);
143	    if (checked) {
144	      setNamespace(os?.baseImageNamespace);
145	      setPvcName(pvcName && !os ? '' : os?.baseImageName);
146	      return;
147	    }
148	    setNamespace(ns);
149	  };
150	
151	  const handleOs = (newOs: string) => {
152	    const operatingSystem = operatingSystems?.find((o) => o.id === newOs);
153	    setOs(operatingSystem);
154	    setPvcName(operatingSystem?.baseImageName);
155	    operatingSystem?.baseImageNamespace && setNamespace(operatingSystem.baseImageNamespace);
156	  };
157	
158	  const handlePvcSizeTemplate = (checked: boolean) => {
159	    setPvcSizeFromTemplate(checked);
160	    setRequestSizeValue(
161	      checked
162	        ? os?.baseImageRecomendedSize?.[0] || ''
163	        : getGiBUploadPVCSizeByImage((fileValue as File)?.size)?.toString(),
164	    );
165	  };
166	
167	  useEffect(() => {
168	    !isLoading && osParam && handleOs(osParam);
169	    // eslint-disable-next-line react-hooks/exhaustive-deps
170	  }, [isLoading]);
171	
172	  useEffect(() => {
173	    const goldenImagePVC = goldenPvcs?.find(
174	      (pvc) => getName(pvc) === os?.baseImageName && getNamespace(pvc) === os?.baseImageNamespace,
175	    );
176	    if (goldenImagePVC) {
177	      setOsImageExists(true);
178	      setDisableFormSubmit(true);
179	      return;
180	    }
181	    if (osImageExists) {
182	      setOsImageExists(false);
183	      setDisableFormSubmit(false);
184	    }
185	    // eslint-disable-next-line react-hooks/exhaustive-deps
186	  }, [goldenPvcs, os]);
187	
188	  return (
189	    <div>
190	      <div className="form-group">
191	        <Alert isInline title={t('Persistent Volume Claim creation')} variant={AlertVariant.info}>
192	          {t(
193	            'This Persistent Volume Claim will be created using a DataVolume through Containerized Data Importer (CDI)',
194	          )}
195	        </Alert>
196	      </div>
197	      <label className="control-label co-required" htmlFor="file-upload">
198	        {t('Upload data')}
199	      </label>
200	      <div className="form-group">
201	        <FileUpload
202	          dropzoneProps={{
203	            accept: { 'application/*': ['.iso,.img,.qcow2,.gz,.xz'] },
204	            onDropAccepted: () => setIsFileRejected(false),
205	            onDropRejected: () => setIsFileRejected(true),
206	          }}
207	          onClearClick={(event) => {
208	            handleFileChange(event, null);
209	            handleFileNameChange(event, '');
210	          }}
211	          onFileInputChange={(event, file: File) => {
212	            handleFileChange(event, file);
213	            handleFileNameChange(event, file.name);
214	          }}
215	          browseButtonText="Upload"
216	          filename={fileName}
217	          filenamePlaceholder="Drag and drop a file or upload one"
218	          hideDefaultPreview
219	          id="file-upload"
220	          value={fileValue}
221	        />
222	        {operatingSystemHaveDV && (
223	          <Checkbox
224	            className="kv--create-upload__golden-switch"
225	            data-checked-state={isGolden}
226	            id="golden-os-switch"
227	            isChecked={isGolden}
228	            label={t('Attach this data to a Virtual Machine operating system')}
229	            onChange={(_event, checked: boolean) => handleGoldenCheckbox(checked)}
230	          />
231	        )}
232	      </div>
233	      {isGolden && (
234	        <UploadPVCFormGoldenImage
235	          goldenPvcs={goldenPvcs}
236	          handleCDROMChange={(checked: boolean) => setMountAsCDROM(checked)}
237	          handleOs={handleOs}
238	          handlePvcSizeTemplate={handlePvcSizeTemplate}
239	          isLoading={isLoading}
240	          mountAsCDROM={mountAsCDROM}
241	          namespace={namespace}
242	          operatingSystems={operatingSystems}
243	          os={os}
244	          osImageExists={osImageExists}
245	          pvcSizeFromTemplate={pvcSizeFromTemplate}
246	        />
247	      )}
248	      <UploadPVCFormPVCName
249	        handlePvcName={(event) => setPvcName(event.currentTarget.value)}
250	        isGolden={isGolden}
251	        isLoading={isLoading}
252	        pvcName={pvcName}
253	      />
254	      <div className="form-group">
255	        <Split hasGutter>
256	          <SplitItem className="kv--create-upload__flexitem">
257	            <UploadPVCFormStorageClass
258	              applySP={applySP}
259	              setApplySP={setApplySP}
260	              setStorageClassName={setStorageClassName}
261	              storageClasses={storageClasses}
262	              storageClassName={storageClassName}
263	            />
264	          </SplitItem>
265	          <SplitItem className="kv--create-upload__flexitem">
266	            <UploadPVCFormSize
267	              requestSizeUnit={requestSizeUnit}
268	              requestSizeValue={requestSizeValue}
269	              setRequestSizeUnit={setRequestSizeUnit}
270	              setRequestSizeValue={setRequestSizeValue}
271	            />
272	          </SplitItem>
273	        </Split>
274	      </div>
275	      {!spLoaded && !loadError ? (
276	        <Loading />
277	      ) : (
278	        <UploadPVCFormMode
279	          accessMode={spAccessMode?.[0]}
280	          applySP={applySP}
281	          setAccessMode={setAccessMode}
282	          setVolumeMode={setVolumeMode}
283	          storageClasses={storageClasses}
284	          storageClassName={storageClassName}
285	          volumeMode={volumeMode ?? spVolumeMode}
286	        />
287	      )}
288	    </div>
289	  );
290	};
291	
292	export default UploadPVCForm;

